class Solution:
    def sortJumbled(self, mapping, nums):
        def mapped(x):
            digits = str(x)
            return int(''.join(str(mapping[int(ch)]) for ch in digits))

        order = sorted(range(len(nums)), key=lambda i: mapped(nums[i]))
        return [nums[i] for i in order]

