class Solution:
    def sortJumbled(self, mapping, nums):
        def mapped(x):
            if x == 0:
                return mapping[0]
            digits = []
            y = x
            while y > 0:
                digits.append(y % 10)
                y //= 10
            val = 0
            for d in reversed(digits):
                val = val * 10 + mapping[d]
            return val

        return sorted(nums, key=mapped)

