var sortJumbled = function(mapping, nums) {
    function mappedVal(x) {
        if (x === 0) return mapping[0];
        let y = x;
        const digits = [];
        while (y > 0) {
            digits.push(y % 10);
            y = Math.floor(y / 10);
        }
        let val = 0;
        for (let i = digits.length - 1; i >= 0; i--) {
            val = val * 10 + mapping[digits[i]];
        }
        return val;
    }
    const idx = nums.map((_, i) => i);
    idx.sort((a, b) => {
        const ma = mappedVal(nums[a]);
        const mb = mappedVal(nums[b]);
        if (ma !== mb) return ma - mb;
        return a - b;
    });
    return idx.map(i => nums[i]);
};
